import re
import urllib.parse
import sys

class Solution:
  def solve(self, attributes):
    href = urllib.parse.urlparse(attributes['href']).hostname
    relSet = set(attributes['rel'].split(','))
    rel = ','.join(list(relSet))
    target = attributes['target'] if attributes['target'] in ['_self', '_blank'] else '_self'
    return { 'href': href, 'rel': rel, 'target': target }

if __name__ == '__main__':
  attributes = {'href': 'https://example.com', 'rel': 'noopener,noreferrer', 'target': '_blank'}
  solution = Solution()
  print(solution.solve(attributes))
